@startuml

package "com" {
  package "qinzhu" {
    package "bean" {

      class Borrow {
        - BorrowId id;
        - Integer punishid;
        - Boolean isreturn;
        - Boolean isrenew;
        - Date time;
      }

      class BorrowId {
        - Integer bookid;
        - Integer readerid;
      }

      class ReaderCat {
        - Integer id;
        - String name;
      }

      class Reader {
        - Integer id;
        - Integer readercat;
        - Integer studentno;
        - String password;
        - String name;
        - String sex;
        - String belong;
        - Integer borrowcount;
        - String picture;
      }

      class Punish {
        - Integer id;
        - Integer hourlong;
        - Float fine;
      }

      class BookCat {
        - Integer id;
        - Integer parentid;
        - Boolean isparent;
        - String name;
      }

      class Book {
        ..列举了部分私有属性..
        - Integer id;
        - Integer bookcat;
        - String bookname;
        - String isbn;
        - String publish;
        - Date pubdate;
      }

      Borrow "1" *-- "1" BorrowId

      ReaderCat "1..*" o-- "1" Reader

      Reader "1" -- "*" Book

      BookCat "1..*" o-- Book

      Reader "1" -- "*" Punish

    }
  }
}

@enduml
